import { Card, Text } from "@nextui-org/react";
import React from "react";

export default function InfoCard() {
  return (
    <Card
      isHoverable
      variant="bordered"
      css={{ mw: "400px" }}
      color="secondary"
    >
      <Card.Body>
        <Text>A hoverable card.</Text>
      </Card.Body>
    </Card>
  );
}
